    "context": "The CPT codes for existing CT studies are IMGCT0491 or IMGIL0001. The CPT code for the new study is 74177.\nCurrent time: 2023-11-07T22:47:00+00:00"
  },
  "behavioral_skills": "",
  "api": {
    "base_url": "http://localhost:8080/fhir/",
    "functions": [
      {
